/**
 * ses-yonetici.js
 * Çocuk eğitim uygulaması — merkezi ses yöneticisi
 *
 * Kullanım:
 *   window.playSes('button_click')
 *   window.playSes('correct')
 *   window.playSes('wrong')
 *   window.playSes('level_complete')
 *   window.playSes('countdown_tick')
 *   window.playSes('time_up')
 *
 *   window.setSesAcik(false)  → sesi kapat
 *   window.setSesAcik(true)   → sesi aç
 */

(function () {
  'use strict';

  var _sesAcik = true;

  // ─── Ses verileri (base64 WAV) ───────────────────────────────────────────
  var SES_DATA = {
    button_click:   'data:audio/wav;base64,',
    correct:        'data:audio/wav;base64,',
    wrong:          'data:audio/wav;base64,',
    level_complete: 'data:audio/wav;base64,',
    countdown_tick: 'data:audio/wav;base64,',
    time_up:        'data:audio/wav;base64,'
  };

  // ─── Paylaşılan AudioContext (Android unlock dahil) ──────────────────────
  var sharedAudioCtx = null;

  function getCtx() {
    if (!sharedAudioCtx || sharedAudioCtx.state === 'closed') {
      sharedAudioCtx = new (window.AudioContext || window.webkitAudioContext)();
    }
    return sharedAudioCtx;
  }

  function unlockAudio() {
    var ctx = getCtx();
    if (ctx.state === 'suspended') ctx.resume();
  }

  // Android / iOS ilk dokunuşta unlock
  document.addEventListener('touchstart', unlockAudio, { once: false, passive: true });
  document.addEventListener('click', unlockAudio, { once: false, passive: true });

  // ─── Ses çalma ───────────────────────────────────────────────────────────
  // Her ses için önceden yüklenmiş AudioBuffer cache
  var _bufferCache = {};

  function _loadBuffer(isim, cb) {
    if (_bufferCache[isim]) { cb(_bufferCache[isim]); return; }
    var dataUrl = SES_DATA[isim];
    if (!dataUrl) { cb(null); return; }
    // data URL → ArrayBuffer
    var base64 = dataUrl.split(',')[1];
    var binary = atob(base64);
    var bytes = new Uint8Array(binary.length);
    for (var i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
    var ctx = getCtx();
    ctx.decodeAudioData(bytes.buffer, function(buffer) {
      _bufferCache[isim] = buffer;
      cb(buffer);
    }, function() { cb(null); });
  }

  function _cal(isim) {
    _loadBuffer(isim, function(buffer) {
      if (!buffer) return;
      var ctx = getCtx();
      var source = ctx.createBufferSource();
      source.buffer = buffer;
      source.connect(ctx.destination);
      source.start(0);
    });
  }

  // ─── Global API ──────────────────────────────────────────────────────────

  window.setSesAcik = function (acik) {
    _sesAcik = !!acik;
  };

  window.playSes = function (isim) {
    if (!_sesAcik) return;
    if (!SES_DATA[isim]) {
      console.warn('[ses-yonetici] Bilinmeyen ses:', isim);
      return;
    }
    try {
      unlockAudio();
      _cal(isim);
    } catch (e) {
      console.warn('[ses-yonetici] Ses çalınamadı:', isim, e);
    }
  };

  // Geriye dönük uyumluluk: hazine.js gibi modüller sharedAudioCtx kullanıyorsa
  Object.defineProperty(window, 'sharedAudioCtx', {
    get: function () { return getCtx(); },
    configurable: true
  });

  // ─── Buton sesi: tüm buton tıklamalarına otomatik ────────────────────────
  document.addEventListener('click', function (e) {
    var el = e.target;
    while (el && el !== document.body) {
      if (el.tagName === 'BUTTON' ||
          el.classList.contains('menu-card-btn') ||
          el.classList.contains('submenu-card') ||
          el.classList.contains('so-metin-kart')) {
        window.playSes('button_click');
        return;
      }
      el = el.parentElement;
    }
  }, { passive: true });

  // ─── Ön yükleme (sayfa yüklenince sessizce cache'le) ─────────────────────
  document.addEventListener('DOMContentLoaded', function () {
    // İlk dokunuşta context açık olmayabilir, sadece cache hazırla
    // Gerçek decode ilk playSes çağrısında olur
  });

  console.log('[ses-yonetici] Yüklendi ✓  — window.playSes() hazır');

})();
